const axios = require('axios');
const crypto = require('crypto');
const fs = require('fs');

const APP_SECRET = 'test_app_secret_1234567890abcdef';
const WEBHOOK_URL = 'http://localhost:3001/api/webhook';
const PHONE_NUMBER_ID = '123456789012345';
const BUSINESS_PHONE = '1234567890';

function generateSignature(payload) {
  const hmac = crypto.createHmac('sha256', APP_SECRET);
  hmac.update(payload);
  return 'sha256=' + hmac.digest('hex');
}

function buildWebhookPayload(messageData) {
  return {
    object: 'whatsapp_business_account',
    entry: [{
      id: `10234567890${messageData.id}`,
      changes: [{
        value: {
          messaging_product: 'whatsapp',
          metadata: {
            display_phone_number: BUSINESS_PHONE,
            phone_number_id: PHONE_NUMBER_ID,
          },
          contacts: [{
            profile: {
              name: messageData.contactName,
            },
            wa_id: messageData.from,
          }],
          messages: [{
            from: messageData.from,
            id: `wamid.${Date.now()}${messageData.id}`,
            timestamp: messageData.timestamp,
            type: 'text',
            text: {
              body: messageData.message,
            },
          }],
        },
        field: 'messages',
      }],
    }],
  };
}

async function sendTestPayloads() {
  const payloads = JSON.parse(fs.readFileSync('./test-payloads.json', 'utf8')).payloads;

  for (const payloadData of payloads) {
    const webhookPayload = buildWebhookPayload(payloadData);
    const payloadString = JSON.stringify(webhookPayload);
    const signature = generateSignature(payloadString);

    try {
      const response = await axios.post(WEBHOOK_URL, webhookPayload, {
        headers: {
          'Content-Type': 'application/json',
          'X-Hub-Signature-256': signature,
        },
      });

      console.log(`[${payloadData.id}] ${payloadData.category}: ${payloadData.message.substring(0, 50)}...`);
      console.log(`  Status: ${response.status} - ${response.statusText}`);
      console.log(`  Expected: ${payloadData.expectedClassification} -> ${payloadData.expectedAction}`);
      console.log('');

      await new Promise(resolve => setTimeout(resolve, 1000));
    } catch (error) {
      console.error(`[${payloadData.id}] Error:`, error.message);
      if (error.response) {
        console.error('  Response:', error.response.status, error.response.statusText);
        console.error('  Data:', error.response.data);
      }
      console.log('');
    }
  }

  console.log('All test payloads sent!');
}

sendTestPayloads().catch(console.error);
